class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def isPalindrome(head: ListNode) -> bool:
    if not head or not head.next:
        return True

    slow = head
    fast = head
    while fast and fast.next:
        slow = slow.next
        fast = fast.next.next

    reversed_second_half = None
    current = slow
    while current:
        next_node = current.next
        current.next = reversed_second_half
        reversed_second_half = current
        current = next_node

    first_half_ptr = head
    while reversed_second_half:
        if first_half_ptr.val != reversed_second_half.val:
            return False
        first_half_ptr = first_half_ptr.next
        reversed_second_half = reversed_second_half.next

    return True
